export interface CommonEventProperties {
    mongosh_version: string;
    session_id: string;
}
export interface IdentifyEvent {
    name: 'Identify';
    payload: {
        platform: string;
        device_id: string;
    };
}
export interface NewConnectionEvent {
    name: 'New Connection';
    payload: {
        is_atlas?: boolean;
        is_localhost?: boolean;
        is_do_url?: boolean;
        server_version?: string;
        server_os?: string;
        server_arch?: string;
        is_enterprise?: boolean;
        auth_type?: string;
        is_data_federation?: boolean;
        is_stream?: boolean;
        dl_version?: string;
        atlas_version?: string;
        is_genuine?: boolean;
        non_genuine_server_name?: string;
        api_version?: string;
        api_strict?: boolean;
        api_deprecation_errors?: boolean;
        node_version?: string;
        is_local_atlas?: boolean;
        is_atlas_url?: boolean;
        atlas_hostname: string | null;
    };
}
export interface StartupTimeEvent {
    name: 'Startup Time';
    payload: {
        is_interactive: boolean;
        js_context: 'repl' | 'plain-vm';
        repl_instantiation?: number;
        user_config_loading?: number;
        driver_setup?: number;
        logging?: number;
        snippet_loading?: number;
        snapshot?: number;
        resource_file_loading?: number;
        async_rewrite?: number;
        eval?: number;
        eval_file?: number;
        telemetry?: number;
        main?: number;
    };
}
export interface ErrorEvent {
    name: 'Error';
    payload: {
        name: string;
        code: unknown;
        scope: unknown;
        metadata: unknown;
    };
}
export interface UseEvent {
    name: 'Use';
}
export interface ShowEvent {
    name: 'Show';
    payload: {
        method: string;
    };
}
export interface ScriptLoadedEvent {
    name: 'Script Loaded';
    payload: {
        nested: boolean;
    };
}
export interface ScriptLoadedCliEvent {
    name: 'Script Loaded CLI';
    payload: {
        nested: boolean;
        shell: boolean;
    };
}
export interface ScriptEvaluatedEvent {
    name: 'Script Evaluated';
    payload: {
        shell: boolean;
    };
}
export interface MongoshrcLoadedEvent {
    name: 'Mongoshrc Loaded';
}
export interface MongorcWarningEvent {
    name: 'Mongorc Warning';
}
export interface SnippetInstallEvent {
    name: 'Snippet Install';
}
export interface ApiCallEvent {
    name: 'API Call';
    payload: {
        class: string;
        method: string;
        count: number;
    };
}
export interface DeprecatedMethodEvent {
    name: 'Deprecated Method';
    payload: {
        class: string;
        method: string;
    };
}
export type TelemetryEvent = IdentifyEvent | NewConnectionEvent | StartupTimeEvent | ErrorEvent | UseEvent | ShowEvent | ScriptLoadedEvent | ScriptLoadedCliEvent | ScriptEvaluatedEvent | MongoshrcLoadedEvent | MongorcWarningEvent | SnippetInstallEvent | ApiCallEvent | DeprecatedMethodEvent;
